import { describe, it, beforeEach } from "node:test";
import { strict as assert } from "node:assert";
import { unwrap } from "../result/result.utils.ts";
import { SlugBuilderImpl } from "./slug-builder-impl.ts";

/**
 * SlugBuilderImpl Test Graph:
 * └── build()
 *     ├── should build a lowercase slug from a title
 *     └── should return an error if title is empty
 */
describe("SlugBuilderImpl", () => {
  let builder: SlugBuilderImpl;

  beforeEach(() => {
    // START_BEFORE_EACH_ARRANGE_SYSTEM_UNDER_TEST
    builder = new SlugBuilderImpl();
    // END_BEFORE_EACH_ARRANGE_SYSTEM_UNDER_TEST
  });

  describe("build()", () => {
    it("should build a lowercase slug from a title", async () => {
      // START_BUILD_SLUG_ARRANGE_INPUT
      const input = { title: "Hello World", separator: "-" };
      // END_BUILD_SLUG_ARRANGE_INPUT

      // START_BUILD_SLUG_ACT
      const slug = await unwrap(builder.build(input));
      // END_BUILD_SLUG_ACT

      // START_BUILD_SLUG_ASSERT
      assert.strictEqual(slug, "hello-world");
      // END_BUILD_SLUG_ASSERT
    });

    it("should return an error if title is empty", async () => {
      // START_BUILD_EMPTY_TITLE_ARRANGE_INPUT
      const input = { title: "", separator: "-" };
      // END_BUILD_EMPTY_TITLE_ARRANGE_INPUT

      // START_BUILD_EMPTY_TITLE_ACT
      const result = await builder.build(input);
      // END_BUILD_EMPTY_TITLE_ACT

      // START_BUILD_EMPTY_TITLE_ASSERT
      assert.strictEqual(result.ok, false);
      assert.match(`${result.error}`, /title is required/i);
      assert.match(`${result.error?.cause}`, /value is not passed/i);
      // END_BUILD_EMPTY_TITLE_ASSERT
    });
  });
});

import { describe, it, beforeEach } from "node:test";
import { strict as assert } from "node:assert";
import { unwrapSync } from "../result/result.utils.ts";
import { UserProfileMapperImpl } from "./user-profile-mapper-impl.ts";

/**
 * UserProfileMapperImpl Test Graph:
 * └── map()
 *     └── should map api payload to the contract shape
 */
describe("UserProfileMapperImpl", () => {
  let mapper: UserProfileMapperImpl;

  beforeEach(() => {
    // START_BEFORE_EACH_ARRANGE_SYSTEM_UNDER_TEST
    mapper = new UserProfileMapperImpl();
    // END_BEFORE_EACH_ARRANGE_SYSTEM_UNDER_TEST
  });

  describe("map()", () => {
    it("should map api payload to the contract shape", () => {
      // START_MAP_PROFILE_ARRANGE_INPUT
      const payload = {
        user_id: "user-123",
        first_name: "Jane",
        last_name: "Doe",
        email: "jane@example.com",
        is_active: true,
      };
      // END_MAP_PROFILE_ARRANGE_INPUT

      // START_MAP_PROFILE_ACT
      const profile = unwrapSync(mapper.map(payload));
      // END_MAP_PROFILE_ACT

      // START_MAP_PROFILE_ASSERT
      assert.deepStrictEqual(profile, {
        id: "user-123",
        displayName: "Jane Doe",
        contacts: {
          email: "jane@example.com",
          phone: null,
        },
        flags: {
          isActive: true,
          isVerified: false,
        },
      });
      // END_MAP_PROFILE_ASSERT
    });
  });
});

import { describe, it, beforeEach, afterEach } from "node:test";
import { strict as assert } from "node:assert";
import { CatalogClient } from "./catalog-client.ts";
import { setupMockAgent } from "../utils/test/mock-http.ts";

/**
 * CatalogClient Test Graph:
 * └── fetchItem()
 *     └── should retry on transient failure and return normalized response
 */
describe("CatalogClient", () => {
  let mockEnv: ReturnType;

  beforeEach(() => {
    // START_BEFORE_EACH_ARRANGE_MOCKS
    mockEnv = setupMockAgent();
    // END_BEFORE_EACH_ARRANGE_MOCKS
  });

  afterEach(() => {
    mockEnv.cleanup();
  });

  describe("fetchItem()", () => {
    it("should retry on transient failure and return normalized response", async () => {
      // START_FETCH_ITEM_RETRY_ARRANGE_MOCKS
      const url = "http://localhost/api/items/42";
      const attemptTracker = mockEnv.interceptMultiple("GET", url, [
        () => ({ status: 503, body: "Service Unavailable" }),
        () => ({ status: 200, body: { id: 42, name: "Keyboard", inStock: true } }),
      ]);
      const client = new CatalogClient({
        retries: 2,
        retryCondition: (error) => error.response?.status === 503,
      });
      // END_FETCH_ITEM_RETRY_ARRANGE_MOCKS

      // START_FETCH_ITEM_RETRY_ACT
      const result = await client.fetchItem(url);
      // Собираем единый срез результата, чтобы diff сразу показывал попытки, статус и payload.
      const actual = {
        attemptCount: attemptTracker.getAttemptCount(),
        ok: result.ok,
        status: result.status,
        data: result.data,
      };
      // END_FETCH_ITEM_RETRY_ACT

      // START_FETCH_ITEM_RETRY_ASSERT
      assert.deepStrictEqual(actual, {
        attemptCount: 2,
        ok: true,
        status: 200,
        data: { id: 42, name: "Keyboard", inStock: true },
      });
      // END_FETCH_ITEM_RETRY_ASSERT
    });
  });
});

import { describe, it, beforeEach } from "node:test";
import { ReportPreviewRenderer } from "./report-preview-renderer.ts";

/**
 * ReportPreviewRenderer Test Graph:
 * ├── renderText()
 * │   └── should match the text snapshot for a report preview
 * │
 * └── renderHtml()
 *     └── should match the html file snapshot for a full report
 */
describe("ReportPreviewRenderer", () => {
  let renderer: ReportPreviewRenderer;

  beforeEach(() => {
    // START_BEFORE_EACH_ARRANGE_SYSTEM_UNDER_TEST
    renderer = new ReportPreviewRenderer();
    // END_BEFORE_EACH_ARRANGE_SYSTEM_UNDER_TEST
  });

  describe("renderText()", () => {
    it("should match the text snapshot for a report preview", (t) => {
      // START_RENDER_TEXT_SNAPSHOT_ARRANGE_INPUT
      const report = {
        id: "report-001",
        title: "Weekly Summary",
        sections: ["Revenue: 1200", "Users: 98"],
      };
      // END_RENDER_TEXT_SNAPSHOT_ARRANGE_INPUT

      // START_RENDER_TEXT_SNAPSHOT_ACT
      const preview = renderer.renderText(report);
      // END_RENDER_TEXT_SNAPSHOT_ACT

      // START_RENDER_TEXT_SNAPSHOT_ASSERT
      t.assert.snapshot(preview);
      // END_RENDER_TEXT_SNAPSHOT_ASSERT
    });
  });

  describe("renderHtml()", () => {
    it("should match the html file snapshot for a full report", (t) => {
      // START_RENDER_HTML_SNAPSHOT_ARRANGE_INPUT
      const report = {
        id: "report-001",
        title: "Weekly Summary",
        sections: ["Revenue: 1200", "Users: 98"],
      };
      // END_RENDER_HTML_SNAPSHOT_ARRANGE_INPUT

      // START_RENDER_HTML_SNAPSHOT_ACT
      const html = renderer.renderHtml(report);
      // END_RENDER_HTML_SNAPSHOT_ACT

      // START_RENDER_HTML_SNAPSHOT_ASSERT
      t.assert.fileSnapshot(html, "./snapshots/report-preview.html");
      // END_RENDER_HTML_SNAPSHOT_ASSERT
    });
  });
});
